using ValoraPesquisa.Application.Contracts; using ValoraPesquisa.Application.DTOs; using ValoraPesquisa.Domain.Entities; using ValoraPesquisa.Domain.Enums;
namespace ValoraPesquisa.Application.Services;
public sealed class PermissionService:IPermissionService{static readonly Dictionary<string,string[]> Map=new(){[Roles.AdminValora]=new[]{SaasActions.ManagePlans,SaasActions.ManageModules,SaasActions.ManageClients,SaasActions.ViewGlobalAudit,SaasActions.ChangeSubscription,SaasActions.ViewReports,SaasActions.ManageOrganization,SaasActions.ManageUsers,SaasActions.CreateForms,SaasActions.CreateSurveys,SaasActions.CreateLinks,SaasActions.ViewResponses,SaasActions.ViewUsage},[Roles.ConsultorValora]=new[]{SaasActions.ViewReports,SaasActions.ViewResponses},[Roles.EmpresaAdmin]=new[]{SaasActions.ManageOrganization,SaasActions.ManageUsers,SaasActions.CreateForms,SaasActions.CreateSurveys,SaasActions.CreateLinks,SaasActions.ViewResponses,SaasActions.ViewUsage},[Roles.GestorPesquisa]=new[]{SaasActions.CreateForms,SaasActions.CreateSurveys,SaasActions.CreateLinks,SaasActions.ViewResponses},[Roles.AnalistaResultados]=new[]{SaasActions.ViewResponses,SaasActions.ViewReports},[Roles.GestorArea]=new[]{SaasActions.ViewResponses,SaasActions.ViewReports},[Roles.Participante]=new[]{SaasActions.AnswerSurveys},[Roles.ConvidadoExterno]=new[]{SaasActions.AnswerSurveys}}; public IReadOnlyList<string> ActionsForRole(string role)=>Map.TryGetValue(role,out var a)?a:Array.Empty<string>(); public EntitlementResultDto Can(CurrentUser u,string action,Guid? org=null){if(u.IsAdminValora)return EntitlementResultDto.Allow(); if(org.HasValue&&u.OrganizationId!=org)return EntitlementResultDto.Deny("ORGANIZATION_SCOPE_DENIED","Usuário não pertence à organização informada."); return ActionsForRole(u.Role).Contains(action)?EntitlementResultDto.Allow():EntitlementResultDto.Deny("PERMISSION_DENIED","Perfil sem permissão para esta ação.");}}
public sealed class PlanService(IPlanRepository repo,IPermissionService permissions):IPlanService{public Task<IReadOnlyList<PlanDto>> ListAsync()=>repo.ListAsync(); public Task<PlanDto?> GetAsync(string code)=>repo.GetByCodeAsync(code); public async Task<PlanDto> CreateAsync(Plan p,CurrentUser u){D(permissions.Can(u,SaasActions.ManagePlans));return await repo.CreateAsync(p);} public async Task<PlanDto> UpdateAsync(Plan p,CurrentUser u){D(permissions.Can(u,SaasActions.ManagePlans));return await repo.UpdateAsync(p);} public Task<PlanLimitDto?> LimitsAsync(string c)=>repo.GetLimitsAsync(c); public Task<IReadOnlyList<PlanCapabilityDto>> CapabilitiesAsync(string c)=>repo.GetCapabilitiesAsync(c); static void D(EntitlementResultDto r){if(!r.Allowed)throw new UnauthorizedAccessException(r.Message);}}
public sealed class ModuleService(IModuleRepository repo,IPermissionService permissions):IModuleService{public Task<IReadOnlyList<ModuleDto>> ListAsync()=>repo.ListAsync(); public Task<IReadOnlyList<OrganizationModuleDto>> ForOrganizationAsync(Guid org)=>repo.ListByOrganizationAsync(org); public async Task<OrganizationModuleDto> SetForOrganizationAsync(Guid org,string code,bool enabled,string source,CurrentUser u){var p=permissions.Can(u,SaasActions.ManageModules,org); if(!p.Allowed)throw new UnauthorizedAccessException(p.Message); return await repo.SetOrganizationModuleAsync(org,code,enabled,source);}}
public sealed class SubscriptionService(ISubscriptionRepository repo,IPermissionService permissions):ISubscriptionService{public Task<SubscriptionDto?> CurrentAsync(Guid org)=>repo.GetCurrentAsync(org); public async Task<SubscriptionDto> ChangePlanAsync(Guid org,string plan,CurrentUser u){var p=permissions.Can(u,SaasActions.ChangeSubscription,org); if(!p.Allowed)throw new UnauthorizedAccessException(p.Message); return await repo.ChangePlanAsync(org,plan);} public async Task<SubscriptionDto> ChangeStatusAsync(Guid org,string st,string bill,CurrentUser u){var p=permissions.Can(u,SaasActions.ChangeSubscription,org); if(!p.Allowed)throw new UnauthorizedAccessException(p.Message); return await repo.ChangeStatusAsync(org,st,bill);}}
public sealed class UsageService(IUsageRepository repo):IUsageService{public Task<UsageMonthlyDto> CurrentAsync(Guid org)=>repo.GetMonthlyAsync(org); public Task<UsageMonthlyDto> RecalculateAsync(Guid org)=>repo.RecalculateAsync(org);}
public sealed class EntitlementService(ISubscriptionRepository subs,IPlanRepository plans,IModuleRepository modules,IUsageRepository usage):IEntitlementService{public async Task<EntitlementResultDto> HasActiveSubscriptionAsync(Guid org){var s=await subs.GetCurrentAsync(org); return s!=null&&(s.Status is "active" or "trial")?EntitlementResultDto.Allow():EntitlementResultDto.Deny("SUBSCRIPTION_INACTIVE","Assinatura inativa.");} public async Task<EntitlementResultDto> CanUseModuleAsync(Guid org,string code){var active=await HasActiveSubscriptionAsync(org); if(!active.Allowed)return active; var mods=await modules.ListByOrganizationAsync(org); return mods.Any(m=>m.ModuleCode==code&&m.Enabled)?EntitlementResultDto.Allow():EntitlementResultDto.Deny("MODULE_NOT_ENABLED","Módulo não habilitado para a organização.");} async Task<EntitlementResultDto> Limit(Guid org,string module,Func<PlanLimitDto,int> lim,Func<UsageMonthlyDto,int> used){var m=await CanUseModuleAsync(org,module); if(!m.Allowed)return m; var s=await subs.GetCurrentAsync(org); var l=s==null?null:await plans.GetLimitsAsync(s.PlanCode); if(l==null)return EntitlementResultDto.Allow(); var limit=lim(l); var u=used(await usage.GetMonthlyAsync(org)); return limit<0||u<limit?EntitlementResultDto.Allow():EntitlementResultDto.Deny("PLAN_LIMIT_REACHED","Limite do plano atingido.",limit,u);} public Task<EntitlementResultDto> CanCreateSurveyAsync(Guid org,bool publishing=false)=>Limit(org,"pesquisas",x=>x.ActiveSurveys,x=>x.ActiveSurveysCount); public Task<EntitlementResultDto> CanCreateFormAsync(Guid org)=>Limit(org,"formularios",x=>x.Forms,x=>x.FormsCount); public Task<EntitlementResultDto> CanCreateUserAsync(Guid org,bool manager=false)=>Limit(org,"usuarios",x=>manager?x.Managers:x.Users,x=>manager?x.ManagersCount:x.UsersCount); public Task<EntitlementResultDto> CanCreateLinkAsync(Guid org)=>Limit(org,"links_publicos",x=>x.PublicLinks,x=>x.PublicLinksCount); public Task<EntitlementResultDto> CanRegisterResponseAsync(Guid org)=>Limit(org,"respostas",x=>x.ResponsesPerMonth,x=>x.ResponsesCount);}
public sealed class DashboardMetricsService(IOrganizationRepository orgs,IUserRepository users,ISurveyRepository surveys,IResponseRepository responses,IAuditService audit,IUsageRepository usage,IPlanRepository plans,ISubscriptionRepository subs,IModuleRepository modules):IDashboardMetricsService{public async Task<DashboardGlobalDto> GlobalAsync(CurrentUser u){if(!u.IsAdminValora)throw new UnauthorizedAccessException("Dashboard global somente para admin_valora."); var o=await orgs.ListAsync(u); var us=await users.ListAsync(u); var sv=await surveys.ListAsync(u); var rs=await responses.ListAsync(u); return new(o.Count,o.Count(x=>x.Status=="active"),o.GroupBy(x=>x.PlanCode).Select(g=>new PlanCountDto(g.Key,g.Count())).ToList(),us.Count,sv.Count(x=>x.Status=="published"),rs.Count(x=>x.CompletedAt>=new DateTimeOffset(DateTime.UtcNow.Year,DateTime.UtcNow.Month,1,0,0,0,TimeSpan.Zero)),0,await audit.ListAsync(u),0);} public async Task<DashboardOrganizationDto> OrganizationAsync(CurrentUser u,Guid? organizationId=null){var org=organizationId??u.OrganizationId??throw new UnauthorizedAccessException("Organização não definida."); if(!u.IsAdminValora&&org!=u.OrganizationId)throw new UnauthorizedAccessException("Acesso negado."); var s=await subs.GetCurrentAsync(org); var l=s==null?null:await plans.GetLimitsAsync(s.PlanCode); var cur=await usage.GetMonthlyAsync(org); var mods=await modules.ListByOrganizationAsync(org); var au=await audit.ListAsync(u); var resp=await responses.ListAsync(u); List<UsageIndicatorDto> ind=new(){I("pesquisas","Pesquisas ativas",cur.ActiveSurveysCount,l?.ActiveSurveys),I("respostas","Respostas no mês",cur.ResponsesCount,l?.ResponsesPerMonth),I("usuarios","Usuários",cur.UsersCount,l?.Users),I("formularios","Formulários",cur.FormsCount,l?.Forms),I("links_publicos","Links públicos",cur.PublicLinksCount,l?.PublicLinks)}; return new(org,s?.PlanCode??"free",s?.PlanName??"Free",s?.Status??"active",ind,mods.Where(x=>x.Enabled).ToList(),resp.Take(10).ToList(),au.Take(10).ToList(),new[]{"Revise o uso mensal.","Publique pesquisas dentro do limite do plano."});} static UsageIndicatorDto I(string c,string l,int u,int? lim)=>new(c,l,u,lim??-1,(lim??-1)<0);}
public sealed class MenuService(IPermissionService permissions,IEntitlementService entitlements):IMenuService{public async Task<IReadOnlyList<MenuItemDto>> GetMenuAsync(CurrentUser u){var org=u.OrganizationId??Guid.Empty; async Task<MenuItemDto> M(string c,string l,string url,string action){var p=permissions.Can(u,action,u.IsAdminValora?null:org); var e=org==Guid.Empty?EntitlementResultDto.Allow():await entitlements.CanUseModuleAsync(org,c); var ok=p.Allowed&&e.Allowed; return new(c,l,url,ok,ok?null:(!p.Allowed?p.Message:e.Message));} var items=new List<MenuItemDto>{new("dashboard","Dashboard","/Home/Dashboard",true)}; items.Add(await M("formularios","Formulários","/Admin/Forms",SaasActions.CreateForms)); items.Add(await M("pesquisas","Pesquisas","/Admin/Surveys",SaasActions.CreateSurveys)); items.Add(await M("links_publicos","Links","/Admin/Links",SaasActions.CreateLinks)); items.Add(await M("respostas","Respostas","/Admin/Responses",SaasActions.ViewResponses)); if(u.IsAdminValora){items.Add(new("planos","Planos","/Admin/Plans",true));items.Add(new("modulos","Módulos","/Admin/Modules",true));items.Add(new("assinaturas","Assinaturas","/Admin/Subscriptions",true));items.Add(new("uso","Uso","/Admin/Usage",true));} return items;}}
